diff --git a/src/containers/Tenant/Query/QueryEditor/monacoTabsManager.ts b/src/containers/Tenant/Query/QueryEditor/monacoTabsManager.ts
new file mode 100644
index 00000000..9625bdbf
--- /dev/null
+++ b/src/containers/Tenant/Query/QueryEditor/monacoTabsManager.ts
@@ -0,0 +1,96 @@
+import type Monaco from 'monaco-editor';
+
+import {YQL_LANGUAGE_ID} from '../../../../utils/monaco/constats';
+
+type MonacoApi = typeof Monaco;
+
+export class MonacoTabsManager {
+    private readonly modelsByTabId = new Map<string, Monaco.editor.ITextModel>();
+    private readonly viewStatesByTabId = new Map<
+        string,
+        Monaco.editor.ICodeEditorViewState | null
+    >();
+    private activeTabId: string | null = null;
+
+    setActiveTabModel(params: {
+        tabId: string;
+        nextValue: string;
+        editor: Monaco.editor.IStandaloneCodeEditor;
+        monaco: MonacoApi;
+        onBeforeSetValue?: (nextValue: string) => void;
+    }) {
+        const {tabId, nextValue, editor, monaco, onBeforeSetValue} = params;
+
+        const prevTabId = this.activeTabId;
+        const isTabSwitch = Boolean(prevTabId && prevTabId !== tabId);
+        if (isTabSwitch && prevTabId) {
+            this.viewStatesByTabId.set(prevTabId, editor.saveViewState());
+        }
+
+        const model = this.getOrCreateModel(tabId, nextValue, monaco);
+        if (model.getValue() !== nextValue) {
+            onBeforeSetValue?.(nextValue);
+            model.setValue(nextValue);
+        }
+
+        const isModelSwitch = editor.getModel() !== model;
+        if (isModelSwitch) {
+            editor.setModel(model);
+        }
+
+        // Restore view state only when actually switching tabs/models.
+        // Restoring on each `nextValue` update causes cursor jumps while typing.
+        if (isTabSwitch || isModelSwitch) {
+            const viewState = this.viewStatesByTabId.get(tabId);
+            if (viewState) {
+                editor.restoreViewState(viewState);
+            }
+        }
+
+        this.activeTabId = tabId;
+        if (isTabSwitch || isModelSwitch) {
+            editor.focus();
+        }
+    }
+
+    disposeRemovedTabs(tabsOrder: readonly string[]) {
+        const tabsSet = new Set(tabsOrder);
+
+        for (const tabId of this.modelsByTabId.keys()) {
+            if (tabsSet.has(tabId)) {
+                continue;
+            }
+
+            const model = this.modelsByTabId.get(tabId);
+            if (model) {
+                model.dispose();
+            }
+            this.modelsByTabId.delete(tabId);
+            this.viewStatesByTabId.delete(tabId);
+
+            if (this.activeTabId === tabId) {
+                this.activeTabId = null;
+            }
+        }
+    }
+
+    disposeAll() {
+        for (const model of this.modelsByTabId.values()) {
+            model.dispose();
+        }
+        this.modelsByTabId.clear();
+        this.viewStatesByTabId.clear();
+        this.activeTabId = null;
+    }
+
+    private getOrCreateModel(tabId: string, initialValue: string, monaco: MonacoApi) {
+        const existingModel = this.modelsByTabId.get(tabId);
+        if (existingModel && !existingModel.isDisposed()) {
+            return existingModel;
+        }
+
+        const model = monaco.editor.createModel(initialValue, YQL_LANGUAGE_ID);
+        this.modelsByTabId.set(tabId, model);
+        return model;
+    }
+}
diff --git a/src/containers/Tenant/Query/QueryEditor/useQueryTabsActions.tsx b/src/containers/Tenant/Query/QueryEditor/useQueryTabsActions.tsx
new file mode 100644
index 00000000..c70cfae1
--- /dev/null
+++ b/src/containers/Tenant/Query/QueryEditor/useQueryTabsActions.tsx
@@ -0,0 +1,116 @@
+import React from 'react';
+
+import {v4 as uuidv4} from 'uuid';
+
+import {
+    addQueryTab,
+    closeQueryTab,
+    renameQueryTab,
+    selectActiveTabId,
+    selectTabsById,
+    selectTabsOrder,
+    setActiveQueryTab,
+} from '../../../../store/reducers/query/query';
+import {useTypedDispatch, useTypedSelector} from '../../../../utils/hooks';
+import i18n from '../i18n';
+
+import {queryManagerInstance} from './helpers';
+
+export function useQueryTabsActions() {
+    const dispatch = useTypedDispatch();
+    const activeTabId = useTypedSelector(selectActiveTabId);
+    const tabsOrder = useTypedSelector(selectTabsOrder);
+    const tabsById = useTypedSelector(selectTabsById);
+    const activeTab = tabsById[activeTabId];
+
+    const handleTabSwitch = React.useCallback(
+        (tabId: string) => {
+            dispatch(setActiveQueryTab({tabId}));
+        },
+        [dispatch],
+    );
+
+    const closeTab = React.useCallback(
+        (tabId: string) => {
+            queryManagerInstance.abortQuery(tabId);
+            dispatch(closeQueryTab({tabId}));
+        },
+        [dispatch],
+    );
+
+    const handleCloseActiveTab = React.useCallback(() => {
+        closeTab(activeTabId);
+    }, [activeTabId, closeTab]);
+
+    const handleDuplicateActiveTab = React.useCallback(() => {
+        if (!activeTab) {
+            return;
+        }
+
+        const tabId = uuidv4();
+        dispatch(
+            addQueryTab({
+                tabId,
+                title: i18n('editor-tabs.duplicate-title', {title: activeTab.title}),
+                input: activeTab.input,
+            }),
+        );
+    }, [activeTab, dispatch]);
+
+    const handleRenameActiveTab = React.useCallback(
+        (title: string) => {
+            dispatch(renameQueryTab({tabId: activeTabId, title}));
+        },
+        [activeTabId, dispatch],
+    );
+
+    const handleNewTabClick = React.useCallback(() => {
+        const tabId = uuidv4();
+        const nextIndex = tabsOrder.length + 1;
+        dispatch(
+            addQueryTab({
+                tabId,
+                title: i18n('editor-tabs.default-title', {index: nextIndex}),
+            }),
+        );
+    }, [dispatch, tabsOrder.length]);
+
+    const activateAdjacentTab = React.useCallback(
+        (direction: -1 | 1) => {
+            if (!tabsOrder.length || tabsOrder.length === 1) {
+                return;
+            }
+
+            const currentIndex = tabsOrder.indexOf(activeTabId);
+            if (currentIndex === -1) {
+                handleTabSwitch(tabsOrder[0]);
+                return;
+            }
+
+            const nextIndex = (currentIndex + direction + tabsOrder.length) % tabsOrder.length;
+            handleTabSwitch(tabsOrder[nextIndex]);
+        },
+        [activeTabId, handleTabSwitch, tabsOrder],
+    );
+
+    const handleNextTab = React.useCallback(() => {
+        activateAdjacentTab(1);
+    }, [activateAdjacentTab]);
+
+    const handlePreviousTab = React.useCallback(() => {
+        activateAdjacentTab(-1);
+    }, [activateAdjacentTab]);
+
+    return {
+        activeTabId,
+        tabsOrder,
+        tabsById,
+        handleTabSwitch,
+        handleNewTabClick,
+        handleCloseActiveTab,
+        handleDuplicateActiveTab,
+        handleRenameActiveTab,
+        handleNextTab,
+        handlePreviousTab,
+    };
+}
