+                    if (isQueryErrorResponse(response)) {
+                        dispatch(
+                            setQueryResult({
+                                tabId,
+                                result: {
+                                    type: actionType,
+                                    error: response,
+                                    isLoading: false,
+                                    queryId,
+                                    startTime,
+                                    endTime: Date.now(),
