+                    dispatch(
+                        setQueryResult({
+                            tabId,
+                            result: {
+                                type: actionType,
+                                data,
+                                isLoading: false,
+                                queryId,
+                                startTime,
+                                endTime: Date.now(),
+                            },
+                        }),
+                    );
+                    return {data: {queryStats, queryId}};
