+                        // This query is no longer current, don't update state
+                        return {error};
+                    }
+                    dispatch(
+                        setQueryResult({
+                            tabId,
+                            result: {
+                                type: actionType,
+                                error,
+                                isLoading: false,
+                                queryId,
+                                startTime,
+                                endTime: Date.now(),
+                            },
+                        }),
+                    );
+                    return {error};
+                }
+            },
+        }),
+        getResourcePools: build.query<string[], {database: string}>({
