+
+function persistDirtyStateToSessionStorage(state: QueryState) {
+    const persistedDirty: QueryTabsDirtyPersistedState = {};
+    for (const [tabId, tab] of Object.entries(state.tabsById)) {
+        persistedDirty[tabId] = tab.isDirty;
+    }
